using System.Security.Claims;using Microsoft.AspNetCore.Http.HttpResults;using Microsoft.EntityFrameworkCore;using QAHub.Api.Domain.TestDesign;using QAHub.Api.Infrastructure.Data;using QAHub.Api.Infrastructure.Security;
namespace QAHub.Api.Features.TestDesign;
public static class TestCaseEndpoints
{
 public static IEndpointRouteBuilder MapTestCaseEndpoints(this IEndpointRouteBuilder endpoints){var g=endpoints.MapGroup("/api/v1/test-cases").WithTags("Test Cases").RequireAuthorization(AuthorizationPolicies.ProductAccess);g.MapGet("/",GetAll);g.MapGet("/export",Export);g.MapPost("/import",Import);g.MapGet("/{id:guid}",GetOne);g.MapPost("/",Create);g.MapPost("/{id:guid}/clone",Clone);g.MapPut("/{id:guid}/coverage",UpdateCoverage);g.MapGet("/{id:guid}/comments",GetComments);g.MapPost("/{id:guid}/comments",AddComment);g.MapGet("/{id:guid}/history",GetHistory);g.MapPut("/{id:guid}/versions/current",Update);g.MapPost("/{id:guid}/versions/current/transitions",Transition);g.MapPost("/{id:guid}/versions",NewVersion);return endpoints;}
 private static async Task<Ok<TestCaseCollectionResponse>> GetAll(QAHubDbContext db,Guid? productId,Guid? requirementId,TestCaseStatus? status,string? search,int page=1,int pageSize=25,CancellationToken ct=default){page=Math.Max(1,page);pageSize=Math.Clamp(pageSize,1,100);var q=from tc in db.TestCases.AsNoTracking()join v in db.TestCaseVersions.AsNoTracking()on new{Id=tc.Id,Version=tc.CurrentVersionNumber}equals new{Id=v.TestCaseId,Version=v.VersionNumber}select new{tc,v};if(productId.HasValue)q=q.Where(x=>x.tc.ProductId==productId);if(requirementId.HasValue)q=q.Where(x=>x.tc.RequirementId==requirementId);if(status.HasValue)q=q.Where(x=>x.v.Status==status);if(!string.IsNullOrWhiteSpace(search)){var term=search.Trim();q=q.Where(x=>x.tc.Code.Contains(term)||x.v.Title.Contains(term)||x.v.Tags.Contains(term));}var count=await q.CountAsync(ct);var items=await q.OrderByDescending(x=>x.v.UpdatedAtUtc).Skip((page-1)*pageSize).Take(pageSize).Select(x=>new TestCaseListItem(x.tc.Id,x.tc.ProductId,x.tc.ModuleId,x.tc.RequirementId,x.tc.Code,x.v.VersionNumber,x.v.Title,x.v.Status,x.v.UpdatedAtUtc)).ToListAsync(ct);return TypedResults.Ok(new TestCaseCollectionResponse(items,page,pageSize,count));}
 private static async Task<Results<Ok<TestCaseResponse>,NotFound>> GetOne(Guid id,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.AsNoTracking().SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var v=await db.TestCaseVersions.AsNoTracking().Include(x=>x.Steps).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);return TypedResults.Ok(ToResponse(tc,v));}
 private static async Task<Results<Created<TestCaseResponse>,ValidationProblem,Conflict>> Create(CreateTestCaseRequest r,QAHubDbContext db,CancellationToken ct){var errors=Validate(r.Code,r.Title,r.Scenario,r.Steps);if(errors.Count>0)return TypedResults.ValidationProblem(errors);if(!await db.Products.AnyAsync(x=>x.Id==r.ProductId&&x.IsActive,ct))return Invalid("productId","Active product is required.");if(r.ModuleId.HasValue&&!await db.ProductModules.AnyAsync(x=>x.Id==r.ModuleId&&x.ProductId==r.ProductId&&x.IsActive,ct))return Invalid("moduleId","Module must belong to product.");if(r.RequirementId.HasValue&&!await db.Requirements.AnyAsync(x=>x.Id==r.RequirementId&&x.ProductId==r.ProductId,ct))return Invalid("requirementId","Requirement must belong to product.");var code=r.Code!.Trim().ToUpperInvariant();if(await db.TestCases.AnyAsync(x=>x.ProductId==r.ProductId&&x.Code==code,ct))return TypedResults.Conflict();if(await IsPotentialDuplicateAsync(r.ProductId,r.Title!,r.Scenario!,db,ct))return TypedResults.ValidationProblem(new Dictionary<string,string[]>{{"title",["A similar test case already exists for this product."]}});var tc=new TestCase(r.ProductId,r.ModuleId,r.RequirementId,code);var v=new TestCaseVersion(tc.Id,1,r.Title!,r.Scenario!,r.Preconditions??"",r.Tags??"");AddSteps(v,r.Steps!);db.TestCases.Add(tc);db.TestCaseVersions.Add(v);await db.SaveChangesAsync(ct);return TypedResults.Created($"/api/v1/test-cases/{tc.Id}",ToResponse(tc,v));}
 private static async Task<Results<Created<TestCaseResponse>,NotFound,Conflict>> Clone(Guid id,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var current=await db.TestCaseVersions.AsNoTracking().Include(x=>x.Steps).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);var code=await CreateUniqueCloneCodeAsync(tc.ProductId,tc.Code,db,ct);var clone=tc.CloneWithVersion(current,code);db.TestCases.Add(clone);db.TestCaseVersions.Add(clone.Versions.Single());await db.SaveChangesAsync(ct);return TypedResults.Created($"/api/v1/test-cases/{clone.Id}",ToResponse(clone,clone.Versions.Single()));}
 private static async Task<Results<Ok<IReadOnlyList<TestCaseCommentResponse>>,NotFound>> GetComments(Guid id,QAHubDbContext db,CancellationToken ct){if(!await db.TestCases.AnyAsync(x=>x.Id==id,ct))return TypedResults.NotFound();var items=await db.TestCaseComments.AsNoTracking().Where(x=>x.TestCaseId==id).OrderByDescending(x=>x.CreatedAtUtc).Select(x=>new TestCaseCommentResponse(x.Id,x.AuthorId,x.Body,x.CreatedAtUtc)).ToListAsync(ct);return TypedResults.Ok<IReadOnlyList<TestCaseCommentResponse>>(items);}
 private static async Task<Results<Created<TestCaseCommentResponse>,NotFound,ValidationProblem>> AddComment(Guid id,CreateTestCaseCommentRequest r,ClaimsPrincipal user,QAHubDbContext db,CancellationToken ct){if(!await db.TestCases.AnyAsync(x=>x.Id==id,ct))return TypedResults.NotFound();if(string.IsNullOrWhiteSpace(r.Body)||r.Body.Trim().Length>4000)return TypedResults.ValidationProblem(new Dictionary<string,string[]>{{"body",["Comment is required and must not exceed 4000 characters."]}});var x=new TestCaseComment(id,user.Identity?.Name??"unknown",r.Body);db.TestCaseComments.Add(x);await db.SaveChangesAsync(ct);return TypedResults.Created($"/api/v1/test-cases/{id}/comments/{x.Id}",new TestCaseCommentResponse(x.Id,x.AuthorId,x.Body,x.CreatedAtUtc));}
 private static async Task<Results<Ok<IReadOnlyList<TestCaseHistoryEntryResponse>>,NotFound>> GetHistory(Guid id,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.AsNoTracking().SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var version=await db.TestCaseVersions.AsNoTracking().SingleOrDefaultAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);if(version is null)return TypedResults.NotFound();var items=await db.TestCaseHistory.AsNoTracking().Where(x=>x.TestCaseVersionId==version.Id).OrderBy(x=>x.OccurredAtUtc).Select(x=>new TestCaseHistoryEntryResponse(x.Id,x.Status,x.ActorId,x.OccurredAtUtc)).ToListAsync(ct);return TypedResults.Ok<IReadOnlyList<TestCaseHistoryEntryResponse>>(items);}
 private static async Task<string> CreateUniqueCloneCodeAsync(Guid productId,string sourceCode,QAHubDbContext db,CancellationToken ct){var baseCode=sourceCode.Trim().ToUpperInvariant();var candidate=baseCode;var suffix=1;while(await db.TestCases.AnyAsync(x=>x.ProductId==productId&&x.Code==candidate,ct)){candidate=$"{baseCode}-COPY-{suffix++}";}return candidate;} private static async Task<bool> IsPotentialDuplicateAsync(Guid productId,string title,string scenario,QAHubDbContext db,CancellationToken ct){var productTestCaseIds=await db.TestCases.AsNoTracking().Where(x=>x.ProductId==productId).Select(x=>x.Id).ToListAsync(ct);if(productTestCaseIds.Count==0)return false;var versions=await db.TestCaseVersions.AsNoTracking().Where(x=>productTestCaseIds.Contains(x.TestCaseId)).Select(x=>new{x.Title,x.Scenario}).ToListAsync(ct);var normalizedTitle=TestCaseVersion.Normalize(title);var normalizedScenario=TestCaseVersion.Normalize(scenario);return versions.Any(x=>TestCaseVersion.Normalize(x.Title)==normalizedTitle&&TestCaseVersion.Normalize(x.Scenario)==normalizedScenario);}
 private static async Task<IResult> Export(QAHubDbContext db,Guid? productId,Guid? requirementId,TestCaseStatus? status,string? search,CancellationToken ct){var q=from tc in db.TestCases.AsNoTracking()join v in db.TestCaseVersions.AsNoTracking()on new{Id=tc.Id,Version=tc.CurrentVersionNumber}equals new{Id=v.TestCaseId,Version=v.VersionNumber}select new{tc,v};if(productId.HasValue)q=q.Where(x=>x.tc.ProductId==productId);if(requirementId.HasValue)q=q.Where(x=>x.tc.RequirementId==requirementId);if(status.HasValue)q=q.Where(x=>x.v.Status==status);if(!string.IsNullOrWhiteSpace(search)){var term=search.Trim();q=q.Where(x=>x.tc.Code.Contains(term)||x.v.Title.Contains(term));}var rows=await q.OrderBy(x=>x.tc.Code).Select(x=>new{x.tc.Code,x.v.Title,x.v.Status,x.tc.ProductId,x.tc.RequirementId,x.v.UpdatedAtUtc}).ToListAsync(ct);static string Csv(object? value)=>$"\"{value?.ToString()?.Replace("\"","\"\"")}\"";var csv=new System.Text.StringBuilder("Code,Title,Status,Product ID,Requirement ID,Updated UTC\r\n");foreach(var x in rows)csv.AppendLine(string.Join(',',Csv(x.Code),Csv(x.Title),Csv(x.Status),Csv(x.ProductId),Csv(x.RequirementId),Csv(x.UpdatedAtUtc)));return Results.File(System.Text.Encoding.UTF8.GetPreamble().Concat(System.Text.Encoding.UTF8.GetBytes(csv.ToString())).ToArray(),"text/csv",$"test-cases-{DateTime.UtcNow:yyyyMMdd}.csv");}
 private static async Task<Ok<ImportTestCasesResponse>> Import(ImportTestCasesRequest r,QAHubDbContext db,CancellationToken ct){var errors=new List<string>();var imported=0;if(string.IsNullOrWhiteSpace(r.Csv))return TypedResults.Ok(new ImportTestCasesResponse(0,["CSV content is required."]));using var parser=new Microsoft.VisualBasic.FileIO.TextFieldParser(new StringReader(r.Csv));parser.SetDelimiters(",");parser.HasFieldsEnclosedInQuotes=true;var headers=parser.ReadFields()??[];var expected=new[]{"Code","Title","Scenario","Preconditions","Tags","Action","TestData","ExpectedResult"};if(!expected.All(headers.Contains))return TypedResults.Ok(new ImportTestCasesResponse(0,["CSV headers must include: "+string.Join(", ",expected)]));var map=headers.Select((x,i)=>(x,i)).ToDictionary(x=>x.x,x=>x.i,StringComparer.OrdinalIgnoreCase);var row=1;while(!parser.EndOfData){row++;var f=parser.ReadFields()??[];try{string V(string n)=>map[n]<f.Length?f[map[n]].Trim():"";var code=V("Code").ToUpperInvariant();if(string.IsNullOrWhiteSpace(code)||await db.TestCases.AnyAsync(x=>x.ProductId==r.ProductId&&x.Code==code,ct)){errors.Add($"Row {row}: invalid or duplicate code.");continue;}var tc=new TestCase(r.ProductId,null,null,code);var v=new TestCaseVersion(tc.Id,1,V("Title"),V("Scenario"),V("Preconditions"),V("Tags"));v.Steps.Add(new TestCaseStep(v.Id,1,V("Action"),V("TestData"),V("ExpectedResult")));db.TestCases.Add(tc);db.TestCaseVersions.Add(v);await db.SaveChangesAsync(ct);imported++;}catch(Exception ex)when(ex is ArgumentException or InvalidOperationException){errors.Add($"Row {row}: invalid data.");}}return TypedResults.Ok(new ImportTestCasesResponse(imported,errors));}
 private static async Task<Results<Ok<TestCaseResponse>,NotFound,ValidationProblem>> UpdateCoverage(Guid id,UpdateTestCaseCoverageRequest r,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();if(r.RequirementId.HasValue&&!await db.Requirements.AnyAsync(x=>x.Id==r.RequirementId&&x.ProductId==tc.ProductId,ct))return Invalid("requirementId","Requirement must belong to product.");if(r.ModuleId.HasValue&&!await db.ProductModules.AnyAsync(x=>x.Id==r.ModuleId&&x.ProductId==tc.ProductId,ct))return Invalid("moduleId","Module must belong to product.");tc.UpdateCoverage(r.RequirementId,r.ModuleId);await db.SaveChangesAsync(ct);var v=await db.TestCaseVersions.AsNoTracking().Include(x=>x.Steps).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);return TypedResults.Ok(ToResponse(tc,v));}
 private static async Task<Results<Ok<TestCaseResponse>,NotFound,ValidationProblem,Conflict>> Update(Guid id,UpdateTestCaseVersionRequest r,QAHubDbContext db,CancellationToken ct){var errors=Validate("existing",r.Title,r.Scenario,r.Steps);if(errors.Count>0)return TypedResults.ValidationProblem(errors);var tc=await db.TestCases.SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var v=await db.TestCaseVersions.Include(x=>x.Steps).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);try{v.Update(r.Title!,r.Scenario!,r.Preconditions??"",r.Tags??"");db.TestCaseSteps.RemoveRange(v.Steps);v.Steps.Clear();AddSteps(v,r.Steps!);await db.SaveChangesAsync(ct);return TypedResults.Ok(ToResponse(tc,v));}catch(InvalidOperationException){return TypedResults.Conflict();}}
 private static async Task<Results<Ok<TestCaseResponse>,NotFound,Conflict>> Transition(Guid id,TransitionTestCaseRequest r,ClaimsPrincipal user,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var v=await db.TestCaseVersions.Include(x=>x.Steps).Include(x=>x.History).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);try{v.TransitionTo(r.Status,user.Identity?.Name);db.TestCaseHistory.Add(v.History[^1]);await db.SaveChangesAsync(ct);return TypedResults.Ok(ToResponse(tc,v));}catch(InvalidOperationException){return TypedResults.Conflict();}}
 private static async Task<Results<Created<TestCaseResponse>,NotFound,Conflict>> NewVersion(Guid id,QAHubDbContext db,CancellationToken ct){var tc=await db.TestCases.SingleOrDefaultAsync(x=>x.Id==id,ct);if(tc is null)return TypedResults.NotFound();var current=await db.TestCaseVersions.AsNoTracking().Include(x=>x.Steps).SingleAsync(x=>x.TestCaseId==id&&x.VersionNumber==tc.CurrentVersionNumber,ct);if(current.Status is not TestCaseStatus.Approved and not TestCaseStatus.Active)return TypedResults.Conflict();tc.AdvanceVersion();var v=new TestCaseVersion(tc.Id,tc.CurrentVersionNumber,current.Title,current.Scenario,current.Preconditions,current.Tags);foreach(var x in current.Steps.OrderBy(x=>x.Sequence))v.Steps.Add(new TestCaseStep(v.Id,x.Sequence,x.Action,x.TestData,x.ExpectedResult));db.TestCaseVersions.Add(v);await db.SaveChangesAsync(ct);return TypedResults.Created($"/api/v1/test-cases/{tc.Id}",ToResponse(tc,v));}
 private static void AddSteps(TestCaseVersion v,IReadOnlyList<TestStepRequest> steps){for(var i=0;i<steps.Count;i++)v.Steps.Add(new TestCaseStep(v.Id,i+1,steps[i].Action!,steps[i].TestData??"",steps[i].ExpectedResult!));}
 private static Dictionary<string,string[]> Validate(string? code,string? title,string? scenario,IReadOnlyList<TestStepRequest>? steps){var e=new Dictionary<string,string[]>();if(string.IsNullOrWhiteSpace(code)||code.Trim().Length>50)e["code"]=["Code is required and must not exceed 50 characters."];if(string.IsNullOrWhiteSpace(title)||title.Trim().Length>250)e["title"]=["Title is required."];if(string.IsNullOrWhiteSpace(scenario))e["scenario"]=["Scenario is required."];if(steps is null||steps.Count==0||steps.Any(x=>string.IsNullOrWhiteSpace(x.Action)||string.IsNullOrWhiteSpace(x.ExpectedResult)))e["steps"]=["At least one step with action and expected result is required."];return e;}
 private static ValidationProblem Invalid(string key,string message)=>TypedResults.ValidationProblem(new Dictionary<string,string[]>{{key,[message]}});
 private static TestCaseResponse ToResponse(TestCase tc,TestCaseVersion v)=>new(tc.Id,tc.ProductId,tc.ModuleId,tc.RequirementId,tc.Code,v.VersionNumber,v.Id,v.Title,v.Scenario,v.Preconditions,v.Tags,v.Status,v.Steps.OrderBy(x=>x.Sequence).Select(x=>new TestStepResponse(x.Id,x.Sequence,x.Action,x.TestData,x.ExpectedResult)).ToList(),v.UpdatedAtUtc);
}
